def nCr(n, r, memo=None):
    if memo is None:
        memo = {}
    if r < 0 or r > n:
        return 0
    if r == 0 or r == n:
        return 1
    key = (n, r)
    if key in memo:
        return memo[key]
    val = nCr(n-1, r-1, memo) + nCr(n-1, r, memo)
    memo[key] = val
    return val

