def rle_encode(s):
    if not s:
        return ''
    parts = []
    count = 1
    prev = s[0]
    for ch in s[1:]:
        if ch == prev:
            count += 1
        else:
            parts.append(f"{count}{prev}")
            prev = ch
            count = 1
    parts.append(f"{count}{prev}")
    return ''.join(parts)

