def moving_average(nums, window):
    if window <= 0:
        raise ValueError('window must be positive')
    if len(nums) < window:
        return []
    cum = 0
    res = []
    for i in range(len(nums)):
        cum += nums[i]
        if i >= window:
            cum -= nums[i - window]
        if i >= window - 1:
            res.append(cum / window)
    return res

