def moving_average(data, k):
    if not data or k <= 0:
        return []
    if k > len(data):
        k = len(data)
    window_sum = sum(data[:k])
    ma = [window_sum / k]
    for i in range(k, len(data)):
        window_sum += data[i] - data[i - k]
        ma.append(window_sum / k)
    return ma

