    if not isinstance(nums, (list, tuple)):
        raise TypeError('nums must be a list or tuple')
    if len(nums) == 0:
        raise ValueError('empty list')
    nums = sorted(nums)
    n = len(nums)
    mid = n // 2
    if n % 2 == 1:
        return nums[mid]
    else:
        return (nums[mid - 1] + nums[mid]) / 2

