import math

def jaro_winkler(s1: str, s2: str) -> float:
    s1, s2 = s1.lower(), s2.lower()
    if s1 == s2:
        return 1.0
    len1, len2 = len(s1), len(s2)
    max_dist = max(len1, len2) // 2 - 1
    match = [False] * max(len1, len2)
    matches = 0
    for i in range(len1):
        start = max(0, i - max_dist)
        end = min(i + max_dist + 1, len2)
        for j in range(start, end):
            if not (j >= len2) and s1[i] == s2[j]:
                match[i] = True
                matches += 1
                break
    if matches == 0:
        return 0.0
    # Count transpositions
    k = 0
    t = 0
    for i in range(len1):
        if match[i]:
            while k < len2 and not (k < len2 and match[k]):
                k += 1
            if k < len2 and s1[i] != s2[k]:
                t += 1
            k += 1
    t //= 2
    m = matches
    jaro = ( (m / len1) + (m / len2) + ((m - t) / m) ) / 3.0
    # Winkler prefix
    prefix = 0
    for i in range(min(4, len1, len2)):
        if s1[i] == s2[i]:
            prefix += 1
        else:
            break
    return jaro + (prefix * 0.1 * (1.0 - jaro))

